fun solve(nums: Array<Long>): Long {
    val n = nums.size
    if (n < 3) return 0L

    // Helper data class to hold (size, cost)
    data class State(val size: Int, val cost: Long) : Comparable<State> {
        // Comparison: Maximize size first, then minimize cost.
        override fun compareTo(other: State): Int {
            if (this.size != other.size) {
                return this.size.compareTo(other.size) // Larger size is 'greater'
            }
            // If sizes are equal, smaller cost is 'greater' (we want to keep it)
            return other.cost.compareTo(this.cost) 
        }
    }

    // Helper to find the better state based on our criteria
    fun betterState(s1: State, s2: State): State {
        return if (s1.compareTo(s2) >= 0) s1 else s2
    }

    // 1. Precalculate C[i]: minimum cost to make index i a peak
    // We only care about indices i from 1 to n-2.
    // We use 1-based indexing for C to match array indices.
    val C = LongArray(n) 
    for (i in 1 until n - 1) {
        // Required value must be > max(nums[i-1], nums[i+1])
        val requiredMin = maxOf(nums[i - 1], nums[i + 1]) + 1
        val cost = maxOf(0L, requiredMin - nums[i])
        C[i] = cost
    }

    // 2. DP setup
    // DP index j corresponds to array index i = j + 1.
    // We need DP states for i = 1 up to n-2. Total n-2 states.
    val numStates = n - 2

    // DP[j][0]: state ending at i=j+1, where i is NOT chosen.
    // DP[j][1]: state ending at i=j+1, where i IS chosen.
    val dp = Array(numStates) { Array(2) { State(0, 0L) } }

    // Base Case: j=0 (i=1)
    // DP[0][0]: Don't pick 1. Size 0, Cost 0.
    dp[0][0] = State(0, 0L) 
    // DP[0][1]: Pick 1. Size 1, Cost C[1].
    dp[0][1] = State(1, C[1])

    // 3. DP Transition
    for (j in 1 until numStates) {
        val i = j + 1 // Current index being evaluated (i = 2 to n-2)

        // DP[j][0]: i is NOT chosen. Take the best result from i-1 (j-1).
        dp[j][0] = betterState(dp[j - 1][0], dp[j - 1][1])

        // DP[j][1]: i IS chosen. Must transition from i-1 NOT chosen (DP[j-1][0]).
        val prevBest = dp[j - 1][0]
        dp[j][1] = State(prevBest.size + 1, prevBest.cost + C[i])
    }

    // 4. Final Result
    // The maximum size/minimum cost solution must end at index n-2 (j = numStates - 1).
    val finalState = betterState(dp[numStates - 1][0], dp[numStates - 1][1])

    return finalState.cost
