fun solve(nums: Array<Long>): Long {
    val n = nums.size
    if (n < 3) return 0L

    // Step 1: Calculate the minimum cost W[i] required to make index i a peak,
    // assuming neighbors are not modified.
    // We only care about indices i = 1 to N-2.
    val w = LongArray(n) // w[i] stores the cost for index i

    for (i in 1 until n - 1) {
        val neighborsMax = maxOf(nums[i - 1], nums[i + 1])
        // Required value: neighborsMax + 1
        // Increase needed: max(0, Required value - Current value)
        val requiredIncrease = neighborsMax + 1 - nums[i]
        w[i] = maxOf(0L, requiredIncrease)
    }

    // Step 2: Dynamic Programming
    // DP_NO[i]: Best result considering peaks up to i, where i is NOT chosen.
    // DP_YES[i]: Best result considering peaks up to i, where i IS chosen.

    // We size DP arrays to N, but only use indices 1 to N-2.
    val dpNo = Array(n) { Result(0, Long.MAX_VALUE) }
    val dpYes = Array(n) { Result(0, Long.MAX_VALUE) }

    // Base Case i=1
    dpNo[1] = Result(0, 0)
    dpYes[1] = Result(1, w[1])

    // Iteration i = 2 to N-2
    for (i in 2 until n - 1) {

        // Calculate DP_NO[i]: i is not a peak. Take the best result from i-1.
        val bestPrev = if (isBetter(dpNo[i-1], dpYes[i-1])) {
            dpNo[i-1]
        } else {
            dpYes[i-1]
        }
        dpNo[i] = bestPrev

        // Calculate DP_YES[i]: i is a peak. Must come from DP_NO[i-1] since i-1 cannot be a peak.
        // Note: dpNo[i-1] must represent a reachable state, otherwise the addition fails logic.
        // Since dpNo[i-1] is initialized to a high cost state, this handles it.
        if (dpNo[i-1].peaks >= 0) {
            val newPeaks = dpNo[i-1].peaks + 1
            val newCost = dpNo[i-1].cost + w[i]
            dpYes[i] = Result(newPeaks, newCost)
        }
    }

    // Step 3: Final Result
    val finalResult = if (isBetter(dpNo[n - 2], dpYes[n - 2])) {
        dpNo[n - 2]
    } else {
        dpYes[n - 2]
    }

    return finalResult.cost
}
