fun solve(nums: Array<Long>): Long {
    val n = nums.size
    if (n < 3) return 0L

    val m = n - 2 // Indices 1 to M are potential peaks

    // 1. Calculate Cost[i] for i = 1 to M
    // We use a 1-based indexing conceptual array for costs, mapped to 0-based storage of size M+1
    val cost = LongArray(m + 1)

    for (i in 1..m) {
        // i corresponds to nums[i]
        val l = nums[i - 1]
        val r = nums[i + 1]

        // Minimum required value for nums'[i] is max(L, R) + 1
        val requiredValue = maxOf(l, r) + 1

        // Cost is max(0, requiredValue - nums[i])
        val c_i = maxOf(0L, requiredValue - nums[i])
        cost[i] = c_i
    }

    // 2. Determine M parity and find minimum cost based on maximal independent set structure

    if (m % 2 != 0) {
        // M is odd. K_max = (M+1)/2. The required set is I = {1, 3, 5, ..., M}.
        var totalCost = 0L
        for (i in 1..m step 2) {
            totalCost += cost[i]
        }
        return totalCost
    } else {
        // M is even. K_max = M/2. We compare I_odd = {1, 3, ..., M-1} and I_even = {2, 4, ..., M}.

        // Calculate cost for I_odd
        var costOdd = 0L
        for (i in 1..m step 2) {
            costOdd += cost[i]
        }

        // Calculate cost for I_even
        var costEven = 0L
        for (i in 2..m step 2) {
            costEven += cost[i]
        }

        return minOf(costOdd, costEven)
    }
}
